content.code:
// Create a variable called "name"
let name = "Aysel";
console.log(name); // Output: Aysel

// Change the variable’s contents
name = "Kamran";
console.log(name); // Output: Kamran

// Block scope example
if (true) {
  let color = "blue";
  console.log(color); // Output: blue
}
// console.log(color); // Error: color is not defined, because it doesn’t exist outside the block

// Hoisting example
// console.log(toy); // Error: Cannot access "toy" before initialization
let toy = "robot";
console.log(toy); // Output: robot

// Redeclaring with let is not allowed
let gadget = "phone";
// let gadget = "earphones"; // Error: gadget has already been declared

// You can change the value
gadget = "earphones";
console.log(gadget); // Output: earphones

// Changing value with const is not allowed
const name = "Kamran";
// name = "Murad"; // Error: Assignment to constant variable

