let name = "Айсель";
console.log(name); // Вывод: Айсель

// Меняем содержимое переменной
name = "Кямран";
console.log(name); // Вывод: Кямран

// Пример блочной области видимости
if (true) {
  let color = "синий";
  console.log(color); // Вывод: синий
}
// console.log(color); // Ошибка: color не определён, так как не существует вне блока

// Пример hoisting
// console.log(toy); // Ошибка: Cannot access "toy" before initialization
let toy = "робот";
console.log(toy); // Вывод: робот

// Повторное объявление с let не допускается
let gadget = "телефон";
// let gadget = "наушники"; // Ошибка: gadget уже объявлена

// Значение можно изменить
gadget = "наушники";
console.log(gadget); // Вывод: наушники

// Изменение значения с const не допускается
const name = "Кямран";
// name = "Мурад"; // Ошибка: Assignment to constant variable

